targets.query:
from(bucket: "vxg_tests")
  |> range(start: -7d)
  |> filter(fn: (r) => r._measurement == "PowerFlatness" and r._field == "pass")
  |> group(columns: ["unit_id"])
  |> reduce(
      fn: (r, accumulator) => ({
        pass_count: accumulator.pass_count + (if r._value == true then 1 else 0),
        fail_count: accumulator.fail_count + (if r._value == false then 1 else 0)
      }),
      identity: {pass_count: 0, fail_count: 0}
    )
  |> group()

from(bucket: "vxg_tests")
  |> range(start: -7d)
  |> filter(fn: (r) => r._measurement == "PowerFlatness" and r._field == "pass")
  |> group(columns: ["unit_id"])
  |> reduce(
      fn: (r, accumulator) => ({any_fail: accumulator.any_fail or (r._value == false)}),
      identity: {any_fail: false}
    )
  |> group()
  |> map(fn: (r) => ({_value: if r.any_fail == false then 1.0 else 0.0, _time: now()}))
  |> mean()
  |> map(fn: (r) => ({_value: r._value * 100.0, _field: "yield_pct", _time: now()}))

from(bucket: "vxg_tests")
  |> range(start: -7d)
  |> filter(fn: (r) => r._measurement == "PowerFlatness" and r._field == "pass")
  |> group(columns: ["unit_id"])
  |> reduce(
      fn: (r, accumulator) => ({any_fail: accumulator.any_fail or (r._value == false)}),
      identity: {any_fail: false}
    )
  |> map(fn: (r) => ({_value: if r.any_fail then 1 else 0, _time: now()}))
  |> group()
  |> sum(column: "_value")
  |> map(fn: (r) => ({_value: r._value, _field: "failing_units", _time: now()}))

import "math"

from(bucket: "vxg_tests")
  |> range(start: -7d)
  |> filter(fn: (r) => r._measurement == "PowerFlatness" and r._field == "power_dbm")
  |> group()
  |> reduce(
      fn: (r, accumulator) => ({
        n:    accumulator.n + 1.0,
        sum:  accumulator.sum + r._value,
        sum2: accumulator.sum2 + r._value * r._value
      }),
      identity: {n: 0.0, sum: 0.0, sum2: 0.0}
    )
  |> map(fn: (r) => {
      mean = r.sum / r.n
      variance = r.sum2 / r.n - mean * mean
      sigma = if variance > 0.0 then math.sqrt(x: variance) else 1.0e-9
      cpu = (0.5 - mean) / (3.0 * sigma)
      cpl = (mean - (-0.5)) / (3.0 * sigma)
      cpk = if cpu < cpl then cpu else cpl
      return {_value: cpk, _field: "cpk", _time: now()}
    })
